INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('7d5079e4-7b9c-4643-ac59-588ae909330f', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'CS-4', 'Safety and Restrictions Compliance', 'Adhere to all range safety procedures.', 4) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('08691235-b202-4833-a43d-46b4b5383f13', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'CS-5', 'Secondary Mission Originality', 'Design and execute a creative secondary mission.', 5) ON CONFLICT DO NOTHING;
INSERT INTO framework_outcomes (id, framework_id, code, label, description, sort_order) VALUES ('bce51d2c-50dc-4702-aa43-169b8160e443', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'CS-6', 'Data Analysis and Documentation Quality', 'Produce thorough post-flight analysis with clear documentation.', 6) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c88501db-537c-448f-a967-fd759b41915b', '0147d901-984d-44c1-a08f-94f919659596', 'technical', 'Technical Content', 'Technical', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('91d2ee22-2b0f-48eb-ac87-5e1fed001650', '0147d901-984d-44c1-a08f-94f919659596', 'design', 'Written Communication', 'Written', 30, 30, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is presented in a way that is accessible to both technical and non-technical readers."},{"min":21,"max":26,"label":"Good","description":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear with small areas for improvement."},{"min":13,"max":20,"label":"Developing","description":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"min":0,"max":12,"label":"Insufficient","description":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('3a305bed-e865-444f-a3a3-c92302bd93cf', '0147d901-984d-44c1-a08f-94f919659596', 'delivery', 'Oral Communication', 'Oral', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('fda374b5-0bbf-41e3-ad46-29fe1491189b', '0147d901-984d-44c1-a08f-94f919659596', 'teamwork', 'Teamwork', 'Teamwork', 10, 10, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"min":7,"max":8,"label":"Good","description":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"min":4,"max":6,"label":"Developing","description":"Uneven participation. Some members are passive or unprepared."},{"min":0,"max":3,"label":"Insufficient","description":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'efe329b2-0a62-4279-a7d1-627abe557321', 'problem_solving', 'Problem Solving & Analysis', 'Problem', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('7283938c-881e-46e5-a432-793287f19248', 'efe329b2-0a62-4279-a7d1-627abe557321', 'system_design', 'System Design & Architecture', 'Design', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c2a960c2-ec12-409c-a49b-14ac9f66a451', 'efe329b2-0a62-4279-a7d1-627abe557321', 'implementation_quality', 'Implementation Quality', 'Impl', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'efe329b2-0a62-4279-a7d1-627abe557321', 'communication', 'Communication & Documentation', 'Comm', 20, 20, '#EC4899', '[{"min":18,"max":20,"label":"Excellent","description":"Documentation is thorough and developer-friendly."},{"min":14,"max":17,"label":"Good","description":"Documentation covers key areas."},{"min":10,"max":13,"label":"Developing","description":"Documentation exists but is incomplete."},{"min":0,"max":9,"label":"Insufficient","description":"Little to no documentation."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('a0ce2f65-e11f-427c-ab49-6806b15b6ffe', 'efe329b2-0a62-4279-a7d1-627abe557321', 'teamwork', 'Teamwork & Collaboration', 'Team', 10, 10, '#10B981', '[{"min":9,"max":10,"label":"Excellent","description":"All members contribute meaningfully."},{"min":7,"max":8,"label":"Good","description":"Most members contribute."},{"min":4,"max":6,"label":"Developing","description":"Uneven contributions."},{"min":0,"max":3,"label":"Insufficient","description":"One or two members did most of the work."}]', 5) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('10f52721-c639-4184-a0c4-1493bd620bfd', '824ead2b-7676-4297-a6e1-507869f5f299', 'preliminary_report', 'Preliminary Design Report (ODR)', 'Report', 25, 25, '#6366F1', '[{"min":22,"max":25,"label":"Excellent","description":"Report is comprehensive with clear mission definition and feasible preliminary design."},{"min":17,"max":21,"label":"Good","description":"Report covers key design elements with adequate justification."},{"min":12,"max":16,"label":"Developing","description":"Report structure is present but design rationale is weak."},{"min":0,"max":11,"label":"Insufficient","description":"Report is incomplete or missing critical sections."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('b58a9de4-d6c7-4143-a851-ed52ef1c7aab', '824ead2b-7676-4297-a6e1-507869f5f299', 'critical_design', 'Critical Design Review (KTR)', 'CDR', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Design is mature, manufacturable, and all subsystems well-integrated."},{"min":21,"max":26,"label":"Good","description":"Design is mostly complete with minor integration gaps."},{"min":13,"max":20,"label":"Developing","description":"Design shows progress but subsystem integration unclear."},{"min":0,"max":12,"label":"Insufficient","description":"Design is immature or not viable for manufacturing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('a408685a-ba52-4173-a90f-b5bcf0b39b63', '824ead2b-7676-4297-a6e1-507869f5f299', 'technical_performance', 'Technical Performance & Demo', 'Performance', 30, 30, '#EF4444', '[{"min":27,"max":30,"label":"Excellent","description":"System performs flawlessly in field conditions."},{"min":21,"max":26,"label":"Good","description":"System completes primary mission with minor deviations."},{"min":13,"max":20,"label":"Developing","description":"System partially completes mission."},{"min":0,"max":12,"label":"Insufficient","description":"System fails to complete primary mission."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('9048c1b4-a5f6-499e-a002-58c2d231a40b', '824ead2b-7676-4297-a6e1-507869f5f299', 'team_execution', 'Team Execution & Presentation', 'Team', 15, 15, '#10B981', '[{"min":14,"max":15,"label":"Excellent","description":"Team operates cohesively with clear role distribution."},{"min":11,"max":13,"label":"Good","description":"Team coordination is evident."},{"min":7,"max":10,"label":"Developing","description":"Team roles are unclear."},{"min":0,"max":6,"label":"Insufficient","description":"Poor team coordination."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('9153ef48-d850-40bf-a60b-985c27b85214', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'originality', 'Originality & Creativity', 'Originality', 35, 35, '#8B5CF6', '[{"min":31,"max":35,"label":"Excellent","description":"Research question is novel and addresses a genuine gap."},{"min":24,"max":30,"label":"Good","description":"Research topic has originality with a clear contribution."},{"min":17,"max":23,"label":"Developing","description":"Topic is relevant but well-trodden."},{"min":0,"max":16,"label":"Insufficient","description":"No original contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ed12bef7-680e-44c5-a2c2-eafd7f911f6b', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'scientific_method', 'Scientific Method & Rigor', 'Method', 40, 40, '#3B82F6', '[{"min":35,"max":40,"label":"Excellent","description":"Hypothesis is clearly stated and testable. Proper controls and adequate sample size."},{"min":27,"max":34,"label":"Good","description":"Methodology is sound with minor gaps."},{"min":19,"max":26,"label":"Developing","description":"Basic methodology present but controls weak."},{"min":0,"max":18,"label":"Insufficient","description":"No clear hypothesis or experimental design."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('b2079523-b082-451d-afaa-b9f1ae7e5141', 'cf0b03e5-576d-4961-a0cc-f86b7852b85f', 'impact_and_presentation', 'Impact & Presentation', 'Impact', 25, 25, '#F59E0B', '[{"min":22,"max":25,"label":"Excellent","description":"Results have clear real-world applicability."},{"min":17,"max":21,"label":"Good","description":"Potential impact is described."},{"min":12,"max":16,"label":"Developing","description":"Impact is mentioned but not convincingly argued."},{"min":0,"max":11,"label":"Insufficient","description":"No discussion of impact."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('87559029-8bad-47de-afc6-43faaa45230b', '8df4448a-b223-4569-a92e-4c81b669b065', 'creativity', 'Creativity & Innovation', 'Creativity', 30, 30, '#EC4899', '[{"min":27,"max":30,"label":"Excellent","description":"Novel topology or technique not commonly seen in literature."},{"min":21,"max":26,"label":"Good","description":"Design shows originality in at least one dimension."},{"min":13,"max":20,"label":"Developing","description":"Conventional approaches with minor modifications."},{"min":0,"max":12,"label":"Insufficient","description":"Direct copy with no meaningful contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ee91d9af-bcf4-49a4-a966-cbd063bbb8f5', '8df4448a-b223-4569-a92e-4c81b669b065', 'technical_merit', 'Technical Merit', 'Technical', 40, 40, '#3B82F6', '[{"min":35,"max":40,"label":"Excellent","description":"Simulation and measurement results agree closely."},{"min":27,"max":34,"label":"Good","description":"Solid results with acceptable agreement."},{"min":19,"max":26,"label":"Developing","description":"Simulation results presented but measurement validation limited."},{"min":0,"max":18,"label":"Insufficient","description":"No measurement results or significant discrepancy."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('03cdba6e-ce74-412d-ab8a-8819efca56ba', '8df4448a-b223-4569-a92e-4c81b669b065', 'application_and_presentation', 'Application & Presentation', 'Presentation', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Clear real-world application with compelling use case."},{"min":21,"max":26,"label":"Good","description":"Application context established."},{"min":13,"max":20,"label":"Developing","description":"Application mentioned but not developed."},{"min":0,"max":12,"label":"Insufficient","description":"No clear application."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('4f8cf9da-b0c7-4a62-ae00-c127f9c6eb8a', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'design_compliance', 'Design Constraints Compliance', 'Compliance', 20, 20, '#6366F1', '[{"min":18,"max":20,"label":"Excellent","description":"All constraints fully met with documented margin analysis."},{"min":14,"max":17,"label":"Good","description":"Constraints met with minor deviations."},{"min":10,"max":13,"label":"Developing","description":"One or more constraints marginally exceeded."},{"min":0,"max":9,"label":"Insufficient","description":"Multiple constraints violated."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('2acdc2ab-1710-48df-a764-c1e4b5e8ec4e', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'mission_execution', 'Mission Execution & Telemetry', 'Mission', 35, 35, '#EF4444', '[{"min":31,"max":35,"label":"Excellent","description":"Primary and secondary missions fully executed. Continuous telemetry."},{"min":24,"max":30,"label":"Good","description":"Primary mission completed. Minor telemetry gaps."},{"min":17,"max":23,"label":"Developing","description":"Primary mission partially completed."},{"min":0,"max":16,"label":"Insufficient","description":"Mission fails to execute."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('7065e7e2-dffe-49f3-a6bf-2d59c6661b90', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'data_and_documentation', 'Data Analysis & Documentation', 'Data', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Flight data thoroughly analyzed with appropriate methods."},{"min":17,"max":21,"label":"Good","description":"Data analysis competent. Post-flight report addresses key findings."},{"min":12,"max":16,"label":"Developing","description":"Data presented but analysis shallow."},{"min":0,"max":11,"label":"Insufficient","description":"Raw data dump with no meaningful analysis."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO framework_criteria (id, framework_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('089917fe-ade5-4d49-a70d-d9b1f8f6d319', '80954c7f-86cc-4d85-aa08-2a6c6d59e7ff', 'safety_and_recovery', 'Safety & Recovery', 'Safety', 20, 20, '#10B981', '[{"min":18,"max":20,"label":"Excellent","description":"Recovered intact. Descent rate within spec. All safety procedures followed."},{"min":14,"max":17,"label":"Good","description":"Recovery successful with minor issues."},{"min":10,"max":13,"label":"Developing","description":"Recovery partial or descent rate deviates."},{"min":0,"max":9,"label":"Insufficient","description":"CanSat lost or damaged."}]', 4) ON CONFLICT DO NOTHING;
